module counter_3bit_updown(CLK, RESET, UP, COUNT);
input CLK;
input RESET;
input UP;
output reg [2:0] COUNT;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RESET or posedge dbg_halt) begin
    if (RESET) begin
        COUNT <= 3'b000;
    end else if (UP) begin
        COUNT <= COUNT + 1;
    end else begin
        COUNT <= COUNT - 1;
    end
end

endmodule
